index 9f034aba874a..c590c5d0a230 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3345,7 +3345,72 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         return new ICmpInst(Pred, BOp0, Neg);
       }
     }
-    break;
+    // Fold (zext A) + (zext B) == C and (sext A) + (sext B) == C
+    // to corresponding boolean logic where A and B are i1.
+    if (BO->hasOneUse()) {
+      // Create APInt constants for comparison
+      const APInt NegOne = APInt::getAllOnes(C.getBitWidth());
+      const APInt NegTwo = NegOne - 1;
+      if (C.isZero() || C.isOne() || C == 2 || C == NegOne || C == NegTwo) {
+        ZExtInst *Z0 = dyn_cast<ZExtInst>(BOp0);
+        ZExtInst *Z1 = dyn_cast<ZExtInst>(BOp1);
+        SExtInst *S0 = dyn_cast<SExtInst>(BOp0);
+        SExtInst *S1 = dyn_cast<SExtInst>(BOp1);
+        Value *A = nullptr;
+        Value *B = nullptr;
+        
+        if (Z0 && Z1 && Z0->getSrcTy()->getScalarSizeInBits() == 1 &&
+            Z1->getSrcTy()->getScalarSizeInBits() == 1) {
+          A = Z0->getOperand(0);
+          B = Z1->getOperand(0);
+          // zext + zext patterns: 0->!(A||B), 1->A^B, 2->A&&B
+          if (C.isZero()) {
+            Value *Or = Builder.CreateOr(A, B);
+            Value *Xor = Builder.CreateXor(Or, ConstantInt::getTrue(Cmp.getType()));
+            return new ICmpInst(Pred, Xor, ConstantInt::getTrue(Cmp.getType()));
+          } else if (C.isOne()) {
+            Value *Xor = Builder.CreateXor(A, B);
+            return new ICmpInst(Pred, Xor, ConstantInt::getTrue(Cmp.getType()));
+          } else if (C == 2) {
+            Value *And = Builder.CreateAnd(A, B);
+            return new ICmpInst(Pred, And, ConstantInt::getTrue(Cmp.getType()));
+          }
+        } else if (S0 && S1 && S0->getSrcTy()->getScalarSizeInBits() == 1 &&
+                   S1->getSrcTy()->getScalarSizeInBits() == 1) {
+          A = S0->getOperand(0);
+          B = S1->getOperand(0);
+          // sext + sext patterns: -2->A&&B, -1->A^B, 0->!(A||B), 1/2->false
+          if (C == NegTwo) {
+            Value *And = Builder.CreateAnd(A, B);
+            return new ICmpInst(Pred, And, ConstantInt::getTrue(Cmp.getType()));
+          } else if (C == NegOne) {
+            Value *Xor = Builder.CreateXor(A, B);
+            return new ICmpInst(Pred, Xor, ConstantInt::getTrue(Cmp.getType()));
+          } else if (C.isZero()) {
+            Value *Or = Builder.CreateOr(A, B);
+            Value *Xor = Builder.CreateXor(Or, ConstantInt::getTrue(Cmp.getType()));
+            return new ICmpInst(Pred, Xor, ConstantInt::getTrue(Cmp.getType()));
+          } else if (C.isOne() || C == 2) {
+            return new ICmpInst(Pred, ConstantInt::getTrue(Cmp.getType()),
+                                ConstantInt::getFalse(Cmp.getType()));
+          }
+        } else {
+          // Mixed zext + sext: can only fold impossible comparisons to false
+          // Sum can be: -1, 0, 1; cannot be -2 or 2
+          if (S0 && Z1 && S0->getSrcTy()->getScalarSizeInBits() == 1 &&
+              Z1->getSrcTy()->getScalarSizeInBits() == 1 &&
+              (C == NegTwo || C == 2)) {
+            return new ICmpInst(Pred, ConstantInt::getTrue(Cmp.getType()),
+                                ConstantInt::getFalse(Cmp.getType()));
+          } else if (Z0 && S1 && Z0->getSrcTy()->getScalarSizeInBits() == 1 &&
+                     S1->getSrcTy()->getScalarSizeInBits() == 1 &&
+                     (C == NegTwo || C == 2)) {
+            return new ICmpInst(Pred, ConstantInt::getTrue(Cmp.getType()),
+                                ConstantInt::getFalse(Cmp.getType()));
+          }
+        }
+      }
+    }
   }
